 	if (result) {
 		goto err_freqfree;
 	}
@@ -346,6 +346,7 @@
 			(u32) data->acpi_data.states[i].power,
 			(u32) data->acpi_data.states[i].transition_latency);

+	cpufreq_frequency_table_get_attr(data->freq_table, policy->cpu);
 	return_VALUE(result);

  err_freqfree:
@@ -370,6 +371,7 @@
